                {`${row.className}`}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box
                component="span"
                sx={{
                  color: 'inherit',
                  typography: 'body2',
                  display: 'flex',
                  flexWrap: 'wrap',
                  gap: 1,
                }}
              >
                {row.sections?.length > 0
                  ? row.sections.map((section) => (
                      <Chip key={section} label={section} size="small" variant="soft" />
                    ))
                  : '-'}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body2' }}>
                {fNumber(row.annualFee) || '-'}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ display: 'flex', justifyContent: 'center', gap: 1 }}>
            <Tooltip title="Edit" placement="top" arrow>
              <IconButton onClick={() => setEditId(row.classId)} color="primary">
                <Iconify icon="solar:pen-bold" />
              </IconButton>
            </Tooltip>
            <Tooltip title="Delete" placement="top" arrow>
              <IconButton color="error" onClick={() => confirmDialog.onTrue()}>
                <Iconify icon="solar:trash-bin-trash-bold" />
              </IconButton>
            </Tooltip>
          </Box>
        </TableCell>
      </TableRow>
      <ClassDialog
        open={Boolean(editId)}
        id={editId}
        onClose={() => setEditId(null)}
        onSuccess={onSuccess}
      />
      {renderConfirmDialog()}
    </>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { LoadingButton } from '@mui/lab';
import {
  Button,
  CircularProgress,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Stack,
} from '@mui/material';
import { useEffect, useState } from 'react';
import { FormProvider, useForm } from 'react-hook-form';
import { z as zod } from 'zod';
import { Field } from 'src/components/hook-form';
import { toast } from 'src/components/snackbar';
import ApiService from 'src/services/ApiService';

const SubjectSchema = zod.object({
  subjectName: zod.string().trim().min(1, { message: 'Subject Name is required.' }),
  subjectCode: zod.string().trim().min(1, { message: 'Subject Code is required.' }),
});

const defaultValues = {
  subjectName: '',
  subjectCode: '',
};

export function SubjectDialog({ id, open, onClose, onSuccess }) {
  const [isLoading, setIsLoading] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(false);

  const methods = useForm({
    resolver: zodResolver(SubjectSchema),
    defaultValues,
  });

  const {
    reset,
    setError,
    handleSubmit,
    formState: { isSubmitting },
  } = methods;

  const onSubmit = handleSubmit(async (values) => {
    setIsLoading(true);

    const payload = {
      subjectName: values.subjectName,
      subjectCode: values.subjectCode,
    };

    const response = await ApiService.saveSubjectAsync(payload);

    if (response.data) {
      toast.success(id ? 'Subject updated successfully.' : 'Subject created successfully.');
      onSuccess?.();
      onClose();
      reset(defaultValues);
    } else if (response.errors) {
      response.errors.forEach((error) => {
