import { zodResolver } from '@hookform/resolvers/zod';
import LoadingButton from '@mui/lab/LoadingButton';
import {
  Autocomplete, Box, Button, Card,
  MenuItem, Stack, TextField
} from '@mui/material';
import Grid from '@mui/material/Grid2';
import { useEffect, useState } from 'react';
import { Controller, useForm } from 'react-hook-form';
import { isValidPhoneNumber } from 'react-phone-number-input';
import { useNavigate } from 'react-router';
import { Field, Form, schemaHelper } from 'src/components/hook-form';
import { LoadingScreen } from 'src/components/loading-screen';
import { toast } from 'src/components/snackbar';
import { useParams } from 'src/routes/hooks';
import apiService from 'src/services/ApiService';
import constants from 'src/utils/constants';
import { z as zod } from 'zod';

const StudentSchema = zod.object({
  firstName: zod.string().min(1, { message: 'First Name is required.' }),
  middleName: zod.string().nullable().optional().or(zod.literal('')),
  lastName: zod.string().min(1, { message: 'Last Name is required.' }),
  gender: zod.string().min(1, { message: 'Gender is required.' }),
  dateOfBirth: zod.string({ required_error: 'Date of Birth is required.' }).min(1, { message: 'Date of Birth is required.' }),
  bloodGroup: zod.string().nullable().optional().or(zod.literal('')),
  aadharNo: zod.string().nullable().optional().or(zod.literal('')),
  email: zod.string().min(1, { message: 'Email is required.' }).email({ message: 'Email must be valid.' }),
  mobileNo: schemaHelper.phoneNumber({ isValid: isValidPhoneNumber }),
  addressLine1: zod.string().nullable().optional(),
  city: zod.string().nullable().optional(),
  state: zod.string().nullable().optional(),
  postalCode: zod.string().nullable().optional(),
  fatherName: zod.string().min(1, { message: 'Father Name is required.' }),
  motherName: zod.string().nullable().optional(),
  parentMobile: schemaHelper.phoneNumber({ isValid: isValidPhoneNumber }),
  parentEmail: zod.string().nullable().optional().or(zod.literal('').refine(val => !val || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val), { message: 'Parent Email must be valid.' })),
  parentAadhar: zod.string().nullable().optional().or(zod.literal('')),
  studentClass: zod.any().nullable().refine(val => val !== null, { message: 'Class & Section is required.' }),
  rollNo: zod.string().min(1, { message: 'Roll Number is required.' }),
});

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

export function StudentSaveForm() {
  const navigate = useNavigate();
  const { id } = useParams();
  const [classMasters, setClassMasters] = useState([]);
  const [fetchingData, setFetchingData] = useState(true);

  const defaultValues = {
    firstName: '',
    middleName: '',
    lastName: '',
    gender: '',
    dateOfBirth: '',
    bloodGroup: '',
    aadharNo: '',
    email: '',
    mobileNo: '',
    addressLine1: '',
    city: '',
    state: '',
    postalCode: '',
    fatherName: '',
    motherName: '',
    parentMobile: '',
    parentEmail: '',
    parentAadhar: '',
    studentClass: null,
    rollNo: '',
  };

  const methods = useForm({
    mode: 'onSubmit',
    resolver: zodResolver(StudentSchema),
    defaultValues,
  });

  const {
    control,
    setError,
    handleSubmit,
    formState: { isSubmitting, isLoading, errors },
  } = methods;


  useEffect(() => {
    const fetchData = async () => {
      try {
        const classRes = await apiService.getAllClassMasterSectionsAsync();
        setClassMasters(classRes.data || []);

        if (id) {
          const { data } = await apiService.getStudentDataByIdAsync(id);

          methods.reset({
            ...data,
            studentClass: classRes.data?.find(
              (c) => c.classId === data.classId && (c.sectionId ?? null) === (data.sectionId ?? null)
            ) || null,
          });
        }
      } catch (err) {
        console.error(err);
      } finally {
        setFetchingData(false);
      }
    };

    fetchData();
  }, [id, methods]);

  const onSubmit = handleSubmit(async (values) => {
    const payload = {
      ...values,
      classId: values.studentClass.classId,
      sectionId: values.studentClass.sectionId ?? null,
      ...(id && { studentId: Number(id) }),
    };
    delete payload.studentClass;

    const response = await apiService.saveStudentAsync(payload);
    if (response.data) {
      toast.success(id ? "Student updated successfully." : "Student created successfully.");
      navigate(-1);
      return;
    }
    if (response.errors && response.errors.length > 0) {
      setError(response.errors[0].param || 'email', {
        message: response.errors[0].msg,
      });
    }
  });

  if (fetchingData || isLoading) {
    return <LoadingScreen />;
  }

  return (
    <Form methods={methods} onSubmit={onSubmit}>
      <Grid container spacing={2}>
        <Grid size={{ xs: 12, md: 8 }}>
          <Stack spacing={2}>
            <Card sx={{ p: 3 }}>
              <Stack direction="column" spacing={2}>
                <Box
                  sx={{
                    rowGap: 3,
                    columnGap: 2,
                    display: 'grid',
                    gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                  }}
                >
                  <Field.Text maxLength={50} name="firstName" label="First Name" />
                  <Field.Text maxLength={50} name="middleName" label="Middle Name" />
                  <Field.Text maxLength={50} name="lastName" label="Last Name" />
                  <Field.Text name="email" label="Email" />
                  <Field.Phone
                    name="mobileNo"
                    label="Mobile Number"
                    country={constants.defaultCountryCode}
                    disableCountryCode={true}
                  />

                  <Field.Select name="gender" label="Gender">
                    <MenuItem value="M">Male</MenuItem>
                    <MenuItem value="F">Female</MenuItem>
                    <MenuItem value="O">Other</MenuItem>
                  </Field.Select>

                  <Field.DatePicker name="dateOfBirth" label="Date of Birth" allowFutureDates={false} allowPastDates={true} />

                  <Field.Select name="bloodGroup" label="Blood Group">
                    {BLOOD_GROUPS.map((group) => (
                      <MenuItem key={group} value={group}>
                        {group}
                      </MenuItem>
                    ))}
                  </Field.Select>

                  <Field.Text name="rollNo" label="Roll Number" />
                  <Controller
                    name="studentClass"
                    control={control}
                    render={({ field }) => (
                      <Autocomplete
                        {...field}
                        fullWidth
                        options={classMasters}
                        value={field.value || null}
                        onChange={(event, newValue) => field.onChange(newValue)}
                        getOptionLabel={(option) => {
                          if (!option) return '';
                          return option.sectionName
                            ? `${option.className} - ${option.sectionName}`
                            : option.className || '';
                        }}
                        isOptionEqualToValue={(option, value) => {
                          if (!option || !value) return false;
                          return option.classId === value.classId && option.sectionId === value.sectionId;
                        }}
                        renderInput={(params) => (
                          <TextField
                            {...params}
                            label="Class & Section"
                            placeholder="Select Class & Section"
                            error={!!errors.studentClass}
                            helperText={errors.studentClass?.message}
                          />
                        )}
                      />
                    )}
                  />
                  <Field.Text name="aadharNo" label="Aadhar Number" />
                </Box>
              </Stack>
            </Card>

            <Card sx={{ p: 3 }}>
              <Stack direction="column" spacing={2}>
                <Box
                  sx={{
                    rowGap: 3,
                    columnGap: 2,
                    display: 'grid',
                    gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                  }}
                >
                  <Field.Text name="addressLine1" label="Address" />
                  <Field.Text name="city" label="City" />
                  <Field.Text name="state" label="State" />
                  <Field.Text name="postalCode" label="Postal Code" />
                </Box>
              </Stack>
            </Card>
          </Stack>
        </Grid>

        <Grid size={{ xs: 12, md: 4 }}>
          <Card sx={{ p: 3 }}>
            <Stack direction="column" spacing={3}>
              <Box
                sx={{
                  rowGap: 3,
                  columnGap: 1,
                  display: 'grid',
                  gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(1, 1fr)' },
                }}
              >
                <Field.Text name="fatherName" label="Father Name" />
                <Field.Text name="motherName" label="Mother Name" />
                <Field.Phone
                  name="parentMobile"
                  label="Parent Mobile Number"
                  country={constants.defaultCountryCode}
                  disableCountryCode={true}
                />
                <Field.Text name="parentEmail" label="Parent Email" />
                <Field.Text name="parentAadhar" label="Parent Aadhar Number" />
              </Box>
            </Stack>
          </Card>
        </Grid>

        <Grid item size={{ xs: 12, md: 8 }}>
          <Stack direction="row" justifyContent="space-between">
            <Stack direction="row" spacing={2}>
              <LoadingButton
                type="submit"
                variant="contained"
                color="primary"
                loading={isSubmitting}
              >
                Save
              </LoadingButton>
              <Button
                disabled={isSubmitting}
                variant="outlined"
                color="error"
                onClick={() => navigate(-1)}
              >
                Cancel
              </Button>
            </Stack>
          </Stack>
        </Grid>
      </Grid>
    </Form>
  );
}

import {
  Box,
  Button,
  Card,
  LinearProgress,
  MenuItem,
  Select,
  Stack,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableRow
} from '@mui/material';
import { useSetState } from 'minimal-shared/hooks';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { Iconify } from 'src/components/iconify';
import { toast } from 'src/components/snackbar';
import {
  emptyRows,
  getComparator,
  rowInPage,
  TableEmptyRows,
  TableHeadCustom,
  TableNoData,
  TablePaginationCustom,
  useTable,
} from 'src/components/table';
import { DashboardContent } from 'src/layouts/dashboard';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import { TableToolbar } from 'src/sections/table-toolbar';
import ApiService from 'src/services/ApiService';

import { StudentTableRow } from '../student-table-row';

const FILTEREDTABLEHEAD = [
  { id: 'studentName', label: 'Name', width: '20%' },
  { id: 'mobileNo', label: 'Phone', width: '15%' },
  { id: 'parent', label: 'Parent', width: '20%', sortBy: false },
  { id: 'classId', label: 'Class', width: '15%', sortBy: false },
  { id: 'rollNo', label: 'Roll No', width: '10%' },
  { id: 'updatedDate', label: 'Last Update', width: '15%' },
];

const TABLEHEAD = [
  ...FILTEREDTABLEHEAD,
  { id: '', label: 'Action', width: '10%', sortBy: false, sx: { textAlign: 'center' } },
];

export function StudentListView() {
  const table = useTable({ defaultOrderBy: 'updatedDate', defaultOrder: 'desc' });
  const [isLoading, setIsLoading] = useState(false);
  const [tableData, setTableData] = useState([]);
  const [classMasters, setClassMasters] = useState([]);
  const filters = useSetState({ search: '', classSection: '' });
  const dataInPage = rowInPage(tableData, table.page, table.rowsPerPage);

  const { state: currentFilters, setState: updateFilters } = filters;

  useEffect(() => {
    getStudentList();
    getClassMasters();
  }, []);

  const getStudentList = async () => {
    setIsLoading(true);
    try {
      const { data } = await ApiService.getStudentListAsync();
      if (data) {
        setTableData(data);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const getClassMasters = async () => {
    try {
      const { data } = await ApiService.getAllClassMasterSectionsAsync();
      if (data) {
        setClassMasters(data);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const dataFiltered = useMemo(() => {
    const { search, classSection } = currentFilters;
    const stabilizedThis = tableData.map((el, idx) => [el, idx]);
    stabilizedThis.sort((a, b) => {
      const order = getComparator(table.order, table.orderBy)(a[0], b[0]);
      if (order !== 0) return order;
      return a[1] - b[1];
    });
    let filteredData = stabilizedThis.map((el) => el[0]);
    if (search) {
      const lower = search.toLowerCase();
      filteredData = filteredData.filter((student) => {
        const fullName = student.studentName || `${student.firstName} ${student.lastName}`;
        return (
          fullName.toLowerCase().includes(lower) ||
          (student.email && student.email.toLowerCase().includes(lower)) ||
          (student.rollNo && student.rollNo.toLowerCase().includes(lower)) ||
          (student.fatherName && student.fatherName.toLowerCase().includes(lower)) ||
          (student.parentMobile && student.parentMobile.toLowerCase().includes(lower))
        );
      });
    }
    if (classSection) {
      const [classId, sectionId] = classSection.split('-');
      const selectedOption = classMasters.find(
        (c) => c.classId == classId && (c.sectionId ?? 'null') == sectionId
      );

      filteredData = filteredData.filter((student) => {
        if (student.classId !== undefined && student.classId !== null) {
          const matchesClass = student.classId == classId;
          const matchesSection = (sectionId === 'null' || !sectionId)
            ? (!student.sectionId || student.sectionId == 'null')
            : student.sectionId == sectionId;
          return matchesClass && matchesSection;
        }
        if (selectedOption) {
          const matchesClass = student.className === selectedOption.className;
          const matchesSection = (sectionId === 'null' || !sectionId)
            ? !student.sectionName
            : student.sectionName === selectedOption.sectionName;
          return matchesClass && matchesSection;
        }
        return false;
      });
    }
    return filteredData;
  }, [tableData, table.order, table.orderBy, currentFilters]);

  const handleFilterChange = (newValue, key = 'search') => {
    updateFilters({ [key]: newValue });
  };

  const onDeleteRow = useCallback(
    async (studentId) => {
      const { data, errors } = await ApiService.deleteStudentAsync(studentId);
      if (data) {
        setTableData((prevData) => prevData.filter((row) => row.studentId !== studentId));
        toast.success('Student deleted successfully.');
        table.onUpdatePageDeleteRow(dataInPage.length);
      } else if (errors) {
        toast.error(errors[0].msg);
      }
      return data;
    },
    [table, dataInPage.length]
  );

  return (
    <DashboardContent>
      <CustomBreadcrumbs
        heading="Manage Students"
        links={[
          { name: 'Dashboard', href: '' },
          { name: 'Student', href: paths.dashboard.student.list },
        ]}
        action={
          <Button
            component={RouterLink}
            href={paths.dashboard.student.new}
            variant="contained"
            color="primary"
            startIcon={<Iconify icon="mingcute:add-line" />}
          >
            New Student
          </Button>
        }
        sx={{ mb: { xs: 2, md: 2 } }}
      />
      <Card>
        <TableToolbar
          filters={filters}
          onFilterChange={handleFilterChange}
          placeholder={'Search By Name or Roll No or Parent'}
        >
          <Select
            name="classSection"
            size="small"
            sx={{ mr: 2, minWidth: 160, textAlign: 'left' }}
            value={filters.state.classSection ?? ''}
            onChange={(e) => handleFilterChange(e.target.value, 'classSection')}
            displayEmpty
          >
            <MenuItem value="">
              <em>All Classes</em>
            </MenuItem>
            {classMasters.map((option) => (
              <MenuItem
                key={`${option.classId}-${option.sectionId ?? 'null'}`}
                value={`${option.classId}-${option.sectionId ?? 'null'}`}
              >
                {option.sectionName ? `${option.className} - ${option.sectionName}` : option.className}
              </MenuItem>
            ))}
          </Select>
        </TableToolbar>
        <TableContainer sx={{ height: 'calc(100vh - 40vh)' }}>
          <Box sx={{ position: 'relative' }}>
            <Table stickyHeader aria-label="sticky table" size={table.dense ? 'small' : 'medium'}>
              <TableHeadCustom
                order={table.order}
                orderBy={table.orderBy}
                headCells={TABLEHEAD}
                rowCount={dataFiltered.length}
                numSelected={table.selected.length}
                onSort={table.onSort}
              />
              {isLoading ? (
                <TableBody>
                  <TableRow>
                    <TableCell colSpan={TABLEHEAD.length}>
                      <Box
                        sx={{
                          display: 'flex',
                          justifyContent: 'center',
                          alignItems: 'center',
                          height: '100%',
                          width: '100%',
                        }}
                      >
                        <Stack alignItems="center" justifyContent="center" sx={{ width: '100%' }}>
                          <LinearProgress sx={{ width: '50%', maxWidth: 360 }} />
                        </Stack>
                      </Box>
                    </TableCell>
                  </TableRow>
                </TableBody>
              ) : (
                <TableBody>
                  <TableNoData label="No student found." notFound={dataFiltered.length <= 0} />
                  {dataFiltered
                    .slice(
                      table.page * table.rowsPerPage,
                      table.page * table.rowsPerPage + table.rowsPerPage
                    )
                    .map((row) => (
                      <StudentTableRow
                        key={row.studentId}
                        row={row}
                        selected={table.selected.includes(row.studentId)}
                        onDeleteRow={() => onDeleteRow(row.studentId)}
                      />
                    ))}
                  <TableEmptyRows
                    height={table.dense ? 56 : 56 + 20}
                    emptyRows={emptyRows(table.page, table.rowsPerPage, tableData.length)}
                  />
                </TableBody>
              )}
            </Table>
          </Box>
        </TableContainer>
        <TablePaginationCustom
          page={table.page}
          dense={table.dense}
          count={filters ? dataFiltered.length : tableData.length}
          rowsPerPage={table.rowsPerPage}
          onPageChange={table.onChangePage}
          onChangeDense={table.onChangeDense}
          onRowsPerPageChange={table.onChangeRowsPerPage}
        />
      </Card>
    </DashboardContent>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import LoadingButton from '@mui/lab/LoadingButton';
import {
  Autocomplete,
  Box,
  Button,
  Card,
  Checkbox,
  Chip,
  IconButton,
  InputAdornment,
  MenuItem,
  Stack,
  TextField,
} from '@mui/material';
import Grid from '@mui/material/Grid2';
import { useBoolean } from 'minimal-shared/hooks';
import { useEffect, useState } from 'react';
import { Controller, useForm } from 'react-hook-form';
import { isValidPhoneNumber } from 'react-phone-number-input';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router';
import { Field, Form, schemaHelper } from 'src/components/hook-form';
import { Iconify } from 'src/components/iconify';
import { LoadingScreen } from 'src/components/loading-screen';
import { toast } from 'src/components/snackbar';
import { useParams } from 'src/routes/hooks';
import apiService from 'src/services/ApiService';
import constants from 'src/utils/constants';
import { z as zod } from 'zod';

const TeacherSchema = zod.object({
  firstName: zod.string().min(1, { message: 'First Name is required.' }),
  lastName: zod.string().min(1, { message: 'Last Name is required.' }),
  email: zod
    .string()
    .min(1, { message: 'Email is required.' })
    .email({ message: 'Email must be valid.' }),
  mobileNo: schemaHelper.phoneNumber({ isValid: isValidPhoneNumber }),
  roleId: zod.coerce.number().refine((val) => val > 0, { message: 'Role is required.' }),
  employmentTypeId: zod.coerce
    .number()
    .refine((val) => val > 0, { message: 'Employment Type is required.' }),
  gender: zod.string().min(1, { message: 'Gender is required.' }),
  joiningDate: zod.string().min(1, { message: 'Joining Date is required.' }),
  qualification: zod.array(zod.string()).optional(),
  dateOfBirth: zod.string().optional(),
  addressLine1: zod.string().optional(),
  city: zod.string().optional(),
  state: zod.string().optional(),
  postalCode: zod.string().optional(),
  teacherClasses: zod
    .array(
      zod.object({
        classId: zod.number(),
        sectionId: zod.number().nullable().optional(),
      })
    )
    .optional(),
  teacherSubjects: zod
    .array(
      zod.object({
        subjectId: zod.number(),
      })
    )
    .optional(),
});

const TeacherAddSchema = TeacherSchema.extend({
  password: zod
    .string()
    .min(1, { message: 'Password is required.' })
    .min(8, { message: 'Password must be at least 8 characters.' }),
});

export function TeacherSaveForm() {
  const navigate = useNavigate();
  const { id } = useParams();
  const [roles, setRoles] = useState([]);
  const [employmentTypes, setEmploymentTypes] = useState([]);
  const [subjects, setSubjects] = useState([]);
  const [classMasters, setClassMasters] = useState([]);

  const showPassword = useBoolean();

  const defaultValues = {
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    mobileNo: '',
    roleId: '',
    employmentTypeId: '',
    gender: '',
    dateOfBirth: '',
    joiningDate: '',
    qualification: [],
    addressLine1: '',
    city: '',
    state: '',
    postalCode: '',
    teacherClasses: [],
    teacherSubjects: [],
  };

  const methods = useForm({
    mode: 'onSubmit',
    resolver: zodResolver(id ? TeacherSchema : TeacherAddSchema),
    defaultValues,
  });

  const {
    control,
    setError,
    handleSubmit,
    watch,
    setValue,
    formState: { isSubmitting, isLoading, errors },
  } = methods;

  useEffect(() => {
    const fetchData = async () => {
      const [rolesRes, employmentRes, subjectRes, classRes] = await Promise.all([
        apiService.getRolesAsync(),
        apiService.getEmploymentTypeAsync(),
        apiService.getSubjectAsync(),
        apiService.getAllClassMasterSectionsAsync(),
      ]);

      setRoles(rolesRes.data);
      setEmploymentTypes(employmentRes.data);
      setSubjects(subjectRes.data);
      setClassMasters(classRes.data);

      if (id) {
        const { data } = await apiService.getTeacherDataByIdAsync(id);

        methods.reset({
          ...data,
          qualification: data.qualification ? data.qualification.split(',') : [],
          teacherSubjects: subjectRes.data.filter((s) =>
            data.teacherSubjects.some((ts) => ts.subjectId === s.subjectId)
          ),
          teacherClasses: classRes.data.filter((c) =>
            data.teacherClasses.some(
              (tc) => tc.classId === c.classId && (tc.sectionId ?? null) === (c.sectionId ?? null)
            )
          ),
        });
      }
    };

    fetchData();
  }, [id, methods]);

  const onSubmit = handleSubmit(async (values) => {
    const payload = {
      ...values,
      qualification: (values.qualification || []).join(','),
      teacherClasses: values.teacherClasses.map((tc) => ({
        classId: tc.classId,
        sectionId: tc.sectionId ?? null,
      })),
      teacherSubjects: values.teacherSubjects.map((ts) => ({
        subjectId: ts.subjectId,
      })),
      ...(id && { teacherId: Number(id) }),
    };
    const response = await apiService.saveTeacherAsync(payload);
    if (response.data) {
      toast.success(id ? 'Teacher updated successfully.' : 'Teacher created successfully.');
      navigate(-1);
      return;
    }
    if (response.error) {
      setError(response.error.param, {
        message: response.error.msg,
      });
    }
  });

  return (
    <>
      {isLoading ? (
        <LoadingScreen />
      ) : (
        <>
          <Form methods={methods} onSubmit={onSubmit}>
            <Grid container spacing={2}>
              <Grid size={{ xs: 12, md: 8 }}>
                <Card sx={{ p: 3 }}>
                  <Stack direction="column" spacing={2}>
                    <Box
                      sx={{
                        rowGap: 3,
                        columnGap: 2,
                        display: 'grid',
                        gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(2, 1fr)' },
                      }}
                    >
                      <Field.Text maxLength={50} name="firstName" label="First Name" />
                      <Field.Text maxLength={50} name="lastName" label="Last Name" />
                      <Field.Text name="email" label="Email" />
                      {!id && (
                        <Field.Text
                          name="password"
                          label="Password"
                          placeholder="8+ characters"
                          type={showPassword.value ? 'text' : 'password'}
                          slotProps={{
                            htmlInput: { minLength: 8, maxLength: 25 },
                            inputLabel: { shrink: true },
                            input: {
                              endAdornment: (
                                <InputAdornment position="end">
                                  <IconButton onClick={showPassword.onToggle} edge="end">
                                    <Iconify
                                      icon={
                                        showPassword.value
                                          ? 'solar:eye-bold'
                                          : 'solar:eye-closed-bold'
                                      }
                                    />
                                  </IconButton>
                                </InputAdornment>
                              ),
                            },
                          }}
                        />
                      )}
                      <Field.Phone
                        name="mobileNo"
                        label="Mobile Number"
                        country={constants.defaultCountryCode}
                        disableCountryCode={true}
                      />
                      <Field.Select name="roleId" label="Role">
                        {roles.map((option) => (
                          <MenuItem key={option.roleId} value={option.roleId}>
                            {option.roleName}
                          </MenuItem>
                        ))}
                      </Field.Select>
                      <Field.Select name="employmentTypeId" label="Employment Type">
                        {employmentTypes.map((option) => (
                          <MenuItem key={option.employmentTypeId} value={option.employmentTypeId}>
                            {option.employmentType}
                          </MenuItem>
                        ))}
                      </Field.Select>
                      <Field.Select name="gender" label="Gender">
                        <MenuItem value="M">Male</MenuItem>
                        <MenuItem value="F">Female</MenuItem>
                        <MenuItem value="O">Other</MenuItem>
                      </Field.Select>
                      <Field.DatePicker
                        name="dateOfBirth"
                        label="Date of Birth"
                        allowFutureDates={true}
                        allowPastDates={true}
                      />
                      <Field.DatePicker
                        name="joiningDate"
                        label="Joining Date"
                        allowFutureDates={true}
                        allowPastDates={true}
                      />
                      <Autocomplete
                        multiple
                        freeSolo
                        options={[]}
                        value={watch('qualification') || []}
                        onChange={(event, newValue) => {
                          setValue('qualification', newValue);
                        }}
                        renderInput={(params) => <TextField {...params} label="Qualification" />}
                        renderTags={(selected = [], getTagProps) =>
                          selected.map((option, index) => (
                            <Chip
                              {...getTagProps({ index })}
                              key={option}
                              label={option}
                              size="small"
                              variant="soft"
                            />
                          ))
                        }
                      />
                      <Field.Text name="addressLine1" label="Address" />
                      <Field.Text name="city" label="City" />
                      <Field.Text name="state" label="State" />
                      <Field.Text name="postalCode" label="Postal Code" />
                    </Box>
                  </Stack>
                </Card>
              </Grid>

              <Grid size={{ xs: 12, md: 4 }}>
                <Card sx={{ p: 3 }}>
                  <Stack direction="column" spacing={2}>
                    <Box
                      sx={{
                        rowGap: 3,
                        columnGap: 1,
                        display: 'grid',
                        gridTemplateColumns: { xs: 'repeat(1, 1fr)', sm: 'repeat(1, 1fr)' },
                      }}
                    >
                      <Controller
                        name="teacherSubjects"
                        control={control}
                        render={({ field }) => (
                          <Autocomplete
                            {...field}
                            fullWidth
                            multiple
                            disableCloseOnSelect
                            options={subjects}
                            getOptionLabel={(option) => option.subjectName}
                            onChange={(event, newValue) => field.onChange(newValue)}
                            isOptionEqualToValue={(option, value) =>
                              option.subjectId === value.subjectId
                            }
                            renderInput={(params) => (
                              <TextField
                                {...params}
                                label="Subjects"
                                placeholder="Subjects"
                                error={!!errors.teacherSubjects}
                                helperText={
                                  errors.teacherSubjects ? errors.teacherSubjects.message : ''
                                }
                              />
                            )}
                            renderOption={(props, option) => {
                              const isSelected = field.value.some(
                                (selected) => selected.subjectId === option.subjectId
                              );
                              return (
                                <li {...props} key={option.subjectId}>
                                  <Checkbox size="small" disableRipple checked={isSelected} />
                                  {option.subjectName}
                                </li>
                              );
                            }}
                            renderTags={(selected, getTagProps) =>
                              selected.map((option, index) => (
                                <Chip
                                  {...getTagProps({ index })}
                                  key={option.subjectId}
                                  label={option.subjectName}
                                  size="small"
                                  variant="soft"
                                />
                              ))
                            }
                          />
                        )}
                      />
                      <Controller
                        name="teacherClasses"
                        control={control}
                        render={({ field }) => (
                          <Autocomplete
                            {...field}
                            fullWidth
                            multiple
                            disableCloseOnSelect
                            options={classMasters}
                            value={field.value || []}
                            onChange={(event, newValue) => field.onChange(newValue)}
                            getOptionLabel={(option) =>
                              option.sectionName
                                ? `${option.className} - ${option.sectionName}`
                                : option.className
                            }
                            isOptionEqualToValue={(option, value) =>
                              option.classId === value.classId &&
                              option.sectionId === value.sectionId
                            }
                            renderInput={(params) => (
                              <TextField
                                {...params}
                                label="Classes"
                                placeholder="Classes"
                                error={!!errors.teacherClasses}
                                helperText={errors.teacherClasses?.message}
                              />
                            )}
                            renderOption={(props, option) => {
                              const isSelected = (field.value || []).some(
                                (selected) =>
                                  selected.classId === option.classId &&
                                  selected.sectionId === option.sectionId
                              );

                              return (
                                <li
                                  {...props}
                                  key={`${option.classId}-${option.sectionId ?? 'null'}`}
                                >
                                  <Checkbox size="small" disableRipple checked={isSelected} />
                                  {option.sectionName
                                    ? `${option.className} - ${option.sectionName}`
                                    : option.className}
                                </li>
                              );
                            }}
                            renderTags={(selected, getTagProps) =>
                              (selected || []).map((option, index) => (
                                <Chip
                                  {...getTagProps({ index })}
                                  key={`${option.classId}-${option.sectionId ?? 'null'}`}
                                  label={
                                    option.sectionName
                                      ? `${option.className} - ${option.sectionName}`
                                      : option.className
                                  }
                                  size="small"
                                  variant="soft"
                                />
                              ))
                            }
                          />
                        )}
                      />
                    </Box>
                  </Stack>
                </Card>
              </Grid>
              <Grid item size={{ xs: 12, md: 8 }}>
                <Stack direction="row" justifyContent="space-between">
                  <Stack direction="row" spacing={2}>
                    <LoadingButton
                      type="submit"
                      variant="contained"
                      color="primary"
                      loading={isSubmitting}
                    >
                      Save
                    </LoadingButton>
                    <Button
                      disabled={isSubmitting}
                      variant="outlined"
                      color="error"
                      onClick={() => navigate(-1)}
                    >
                      Cancel
                    </Button>
                  </Stack>
                </Stack>
              </Grid>
            </Grid>
          </Form>
        </>
      )}
    </>
  );
}

import { LoadingButton } from '@mui/lab';
import { Avatar, Box, IconButton, Stack, TableCell, TableRow, Tooltip } from '@mui/material';
import { useBoolean } from 'minimal-shared/hooks';
import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { ConfirmDialog } from 'src/components/custom-dialog';
import { Iconify } from 'src/components/iconify';
import { RouterLink } from 'src/routes/components';
import { paths } from 'src/routes/paths';
import dateHelper from 'src/utils/dateHelper';
import enums from 'src/utils/enums';
import utils from 'src/utils/utils';

export function TeacherTableRow({ row, selected, onDeleteRow, isProfile }) {
  const confirmDialog = useBoolean();
  const [loading, setLoading] = useState(false);

  const methods = useForm({
    defaultValues: {
      authChoice: 'backup',
    },
  });

  const renderConfirmDialog = () => (
    <ConfirmDialog
      open={confirmDialog.value}
      onClose={confirmDialog.onFalse}
      title="Delete Teacher"
      content={<>Are you sure want to delete {row.teacherName}?</>}
      action={
        <LoadingButton
          variant="contained"
          color="error"
          loading={loading}
          onClick={() => {
            utils.handleConfirmDelete({
              setLoading,
              onDeleteRow,
              confirmDialog,
            });
          }}
        >
          Delete
        </LoadingButton>
      }
    />
