                {`${row.teacherName}`}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex' }}>
            <Stack sx={{ typography: 'body2', flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {row.email}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ typography: 'body2', flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {row.mobileNo}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ typography: 'body2', flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit' }}>
                {enums.displayRole[row.roleId]}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body2' }}>
                {row.lastLoginOn ? `${dateHelper.formatDateTime(row.lastLoginOn)}` : '-'}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          <Box sx={{ gap: 2, display: 'flex', alignItems: 'center' }}>
            <Stack sx={{ flex: '1 1 auto', alignItems: 'flex-start' }}>
              <Box component="span" sx={{ color: 'inherit', typography: 'body2' }}>
                {row.updatedBy ?? ''}
              </Box>
              <Box component="span" sx={{ color: 'text.disabled' }}>
                {dateHelper.formatDateTime(row.updatedDate)}
              </Box>
            </Stack>
          </Box>
        </TableCell>
        <TableCell>
          {!isProfile && (
            <Box sx={{ display: 'flex', justifyContent: 'center', gap: 1 }}>
              <Tooltip title="Edit" placement="top" arrow>
                <IconButton
                  component={RouterLink}
                  href={paths.dashboard.teacher.edit(row.teacherId)}
                  color="primary"
                >
                  <Iconify icon="solar:pen-bold" />
                </IconButton>
              </Tooltip>
              <Tooltip title="Delete" placement="top" arrow>
                <IconButton color="error" onClick={() => confirmDialog.onTrue()}>
                  <Iconify icon="solar:trash-bin-trash-bold" />
                </IconButton>
              </Tooltip>
            </Box>
          )}
        </TableCell>
      </TableRow>
      {renderConfirmDialog()}
    </>
  );
}

import { CustomBreadcrumbs } from 'src/components/custom-breadcrumbs';
import { DashboardContent } from 'src/layouts/dashboard';
import { paths } from 'src/routes/paths';
import { useSelector } from 'react-redux';

import { TeacherSaveForm } from '../teacher-save-form';

export function ProfileEditView() {
  const { loggedInTeacher } = useSelector((state) => state.AuthReducer);
  return (
    <DashboardContent>
      <CustomBreadcrumbs
        heading="Edit Profile"
        links={[{ name: 'Dashboard', href: paths.dashboard.root }, { name: 'Edit Profile' }]}
        sx={{ mb: { xs: 2, md: 2 } }}
