}

import PropTypes from 'prop-types';
import { useState, useEffect } from 'react';
import {
  Stack,
  Button,
  Select,
  Dialog,
  MenuItem,
  Typography,
  InputLabel,
  FormControl,
  DialogTitle,
  DialogContent,
  DialogActions,
} from '@mui/material';
import LoadingButton from '@mui/lab/LoadingButton';

// Helper to format time slot label
function formatTime(value) {
  if (!value) return '';
  let hours;
  let minutes;
  if (Array.isArray(value)) {
    [hours, minutes] = value;
  } else if (typeof value === 'string') {
    const [h, m] = value.split(':');
    hours = Number(h);
    minutes = Number(m);
  } else {
    return '';
  }
  if (Number.isNaN(hours) || Number.isNaN(minutes)) return '';
  const period = hours >= 12 ? 'PM' : 'AM';
  const hour12 = hours % 12 === 0 ? 12 : hours % 12;
  return `${String(hour12).padStart(2, '0')}:${String(minutes).padStart(2, '0')} ${period}`;
}

function getRowTimeLabel(row) {
  if (!row) return '';
  const range = [formatTime(row.startTime), formatTime(row.endTime)].filter(Boolean).join(' - ');
  return range || row.slotName || '';
}

export function TimetableEditDialog({
  open,
  onClose,
  row,
  day,
  subjects,
  teachers,
  saving,
  onSave,
}) {
  const [subjectId, setSubjectId] = useState('');
  const [teacherId, setTeacherId] = useState('');

  // Update form fields when the row or day changes (e.g. when opening the dialog)
  useEffect(() => {
    if (open && row && day) {
      const cell = row.cells?.[day] || {};
      setSubjectId(cell.subjectId ?? '');
      setTeacherId(cell.teacherId ?? '');
    }
  }, [open, row, day]);

  const handleSave = () => {
    onSave({
      subjectId: subjectId || null,
      teacherId: teacherId || null,
    });
  };

  return (
    <Dialog open={open} onClose={onClose} maxWidth="xs" fullWidth>
      <DialogTitle sx={{ fontWeight: 'bold' }}>Assign Period</DialogTitle>
      <DialogContent dividers>
        <Stack spacing={2.5} sx={{ mt: 0.5 }}>
          <Typography variant="body2" sx={{ color: 'text.secondary' }}>
            {day} &nbsp;•&nbsp; {getRowTimeLabel(row)}
          </Typography>

          <FormControl fullWidth>
            <InputLabel id="edit-subject-label">Subject</InputLabel>
            <Select
              labelId="edit-subject-label"
              value={subjectId}
              label="Subject"
              onChange={(e) => setSubjectId(e.target.value)}
            >
              <MenuItem value="">
                <em>None</em>
              </MenuItem>
              {subjects.map((sub) => (
                <MenuItem key={sub.subjectId} value={sub.subjectId}>
                  {sub.subjectName}
                </MenuItem>
              ))}
            </Select>
          </FormControl>

          <FormControl fullWidth>
            <InputLabel id="edit-teacher-label">Teacher</InputLabel>
            <Select
              labelId="edit-teacher-label"
              value={teacherId}
              label="Teacher"
              onChange={(e) => setTeacherId(e.target.value)}
            >
              <MenuItem value="">
                <em>None</em>
              </MenuItem>
              {teachers.map((teacher) => (
                <MenuItem key={teacher.teacherId} value={teacher.teacherId}>
                  {teacher.teacherName}
                </MenuItem>
              ))}
            </Select>
          </FormControl>
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose} color="inherit" disabled={saving}>
          Cancel
        </Button>
        <LoadingButton
          onClick={handleSave}
          variant="contained"
          color="success"
          loading={saving}
        >
          Save
        </LoadingButton>
      </DialogActions>
    </Dialog>
  );
}

TimetableEditDialog.propTypes = {
  open: PropTypes.bool.isRequired,
  onClose: PropTypes.func.isRequired,
  row: PropTypes.object,
  day: PropTypes.string,
  subjects: PropTypes.array.isRequired,
  teachers: PropTypes.array.isRequired,
  saving: PropTypes.bool.isRequired,
  onSave: PropTypes.func.isRequired,
};

